def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 0, -2):
                for b in range(1, a + 4):
                    term1 = ((ratio - a) ** 7) / (a * b * 1.1 + 2)
                    term2 = np.sin(ratio * b / (a + 0.5))
                    priority += term1 * term2 * np.exp(-0.1 * (i % (a + b)))
            priority += np.power(np.abs(np.sin(ratio * 2.2)), 3) * np.exp(ratio - 7)
        elif 5 < ratio <= 8:
            s1 = 0
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 3):
                    val = ((ratio - p) ** 4) * np.cos(ratio * p * 1.3) / (q + 1)
                    s1 += np.tanh(val) * 1.5
            s2 = 0
            for r in range(1, 8):
                s2 += np.exp(-r / (ratio + 0.2)) * np.sin(r * ratio * 1.8)
            priority = s1 + s2 + np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
        elif 2 <= ratio <= 5:
            s = 0
            for k in range(1, 15):
                s += ((ratio - 2) ** k) / (k * 2.2) * np.cos(k * ratio * 1.5)
            penalty = 0
            for m in range(1, 5):
                penalty += np.sin(m * ratio * i * 0.9) * ((ratio - 1.9) ** m) / m
            priority = (s * np.cos(9 * ratio)) - np.log(ratio + 0.1) * 7 + np.tanh(3 * (5 - ratio)) * 2 + penalty
        elif 1 < ratio < 2:
            s = 0
            for n in range(1, 13):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.exp(-0.5 * n)
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item * 2 / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for x in range(1, 6):
                priority += np.sin(x * ratio * i * 1.2) * ((ratio - 1) ** x) / (x + 0.5)
        elif 0.5 <= ratio <= 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - ratio) ** n) / (n * 3.5) * np.tanh(n * item * 0.8)
            priority = s
            if (i * int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap * 2) * 1.4
            else:
                priority /= (np.sqrt(bin_cap + 2.8) + 3)
            for j in range(1, 7):
                priority += ((1 - ratio) ** j) * np.cos(j * item * 1.3) * 0.8
        elif 0.2 <= ratio < 0.5:
            s = 0
            for t in range(1, 18):
                s += ((0.5 - ratio) ** t) / (t * 4.5) * np.sin(t * ratio * 2.3)
            priority = s + 1 / (bin_cap + 2.5)
            if int(item * 1.7) % 6 == 0:
                priority *= 3
            else:
                priority /= 3.5
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 5) * np.cos(item * m * 1.2)
        elif 0.05 <= ratio < 0.2:
            s = 0
            for u in range(1, 14):
                s += ((0.2 - ratio) ** u) / (u * 6) * np.cos(u * item * 0.95)
            priority = s + 3 / (bin_cap + 3.5)
            if int(item * 0.9) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for v in range(1, 10):
                priority += ((0.2 - ratio) ** v) / (v * 8) * np.sin(item * v * 0.85)
        else:
            s = 0
            for w in range(1, 12):
                s += ((0.05 - ratio) ** w) / (w * 7) * np.sin(w * item * 1.0)
            priority = s + 4 / (bin_cap + 5)
            if int(item * 0.8) % 6 == 0:
                priority *= 5
            else:
                priority /= 5
            if bin_cap < item * 0.07:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 3) * 6
            for z in range(1, 11):
                priority += ((0.05 - ratio) ** z) / (z * 9) * np.cos(item * z * 0.75)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.1) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if (i * item) % 5 == 0:
            priority += np.tanh(ratio * (i + 1) * 2) * 1.1
        else:
            priority -= np.tanh(ratio * (i + 2) / 2) * 0.9
        priorities[i] = priority
    return priorities
